export default function Navbar() {

  const logout = () => {

    localStorage.removeItem("user");

    window.location = "/";
  };

  return (

    <div style={styles.navbar}>

      {/* LOGO */}

      <h2 style={styles.logo}>
        DailyWorker
      </h2>

      {/* MENU */}

      <div style={styles.menu}>

        <button
          style={styles.homeBtn}
          onClick={() => window.location = "/"}
        >
          Home
        </button>

        <button
          style={styles.logoutBtn}
          onClick={logout}
        >
          Logout
        </button>

      </div>

    </div>
  );
}

const styles = {

  navbar: {
    height: "70px",
    background: "white",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "0 60px",
    boxShadow: "0 2px 10px rgba(0,0,0,0.05)"
  },

  logo: {
    color: "#2563eb",
    fontSize: "24px",
    margin: 0
  },

  menu: {
    display: "flex",
    gap: "15px"
  },

  homeBtn: {
    background: "transparent",
    border: "1px solid #d1d5db",
    padding: "10px 18px",
    borderRadius: "8px",
    cursor: "pointer",
    fontSize: "14px"
  },

  logoutBtn: {
    background: "#ef4444",
    color: "white",
    border: "none",
    padding: "10px 18px",
    borderRadius: "8px",
    cursor: "pointer",
    fontSize: "14px"
  }

};
